#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <algorithm>

// The function to be tested
bool searchMatrix(const std::vector<std::vector<int>>& matrix, int rows, int cols, int target);

// Function to parse the input string and run a single test case
void run_test_case(const std::string& input_str, const std::string& expected_output) {
    std::stringstream ss(input_str);
    std::string matrix_str_raw, rows_str, cols_str, target_str;

    std::getline(ss, matrix_str_raw, ';');
    std::getline(ss, rows_str, ';');
    std::getline(ss, cols_str, ';');
    std::getline(ss, target_str, ';');

    int rows = std::stoi(rows_str);
    int cols = std::stoi(cols_str);
    int target = std::stoi(target_str);

    std::vector<std::vector<int>> matrix;
    if (matrix_str_raw != "[]") {
        std::string matrix_content = matrix_str_raw.substr(2, matrix_str_raw.length() - 4); // Remove outer [[ and ]]
        std::stringstream matrix_ss(matrix_content);
        std::string row_str;
        while (std::getline(matrix_ss, row_str, ']')) {
            if (row_str.empty()) continue;
            if (row_str[0] == ',') row_str = row_str.substr(1); // Remove leading comma if present
            if (row_str[0] == '[') row_str = row_str.substr(1); // Remove leading [

            std::stringstream row_ss(row_str);
            std::string val_str;
            std::vector<int> current_row;
            while (std::getline(row_ss, val_str, ',')) {
                if (!val_str.empty()) {
                    current_row.push_back(std::stoi(val_str));
                }
            }
            matrix.push_back(current_row);
        }
    }

    bool result = searchMatrix(matrix, rows, cols, target);
    std::string actual_output = result ? "true" : "false";

    std::cout << "Input: " << input_str << ", Expected: " << expected_output << ", Got: " << actual_output << " -> ";
    if (actual_output == expected_output) {
        std::cout << "PASS" << std::endl;
    } else {
        std::cout << "FAIL" << std::endl;
    }
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        { "[[1,2,3],[4,5,6],[7,8,9]];3;3;5", "true" },
        { "[[1,2,3],[4,5,6],[7,8,9]];3;3;10", "false" },
        { "[[10]];1;1;10", "true" },
        { "[[10]];1;1;1", "false" },
        { "[];0;0;1", "false" },
        { "[];1;1;1", "false" },
        { "[[1,2,3],[],[4,5]];3;3;1", "true" },
        { "[[1,2,3],[],[4,5]];3;3;4", "true" },
        { "[[1,2,3],[],[4,5]];3;3;6", "false" },
        { "[[1,2],[3,4]];3;3;4", "true" },
        { "[[1,2],[3,4]];3;3;5", "false" },
        { "[[1,2,3],[4,5,6],[7,8,9]];1;1;1", "true" },
        { "[[1,2,3],[4,5,6],[7,8,9]];1;1;5", "false" }
    };

    for (const auto& test_case : test_cases) {
        run_test_case(test_case.first, test_case.second);
    }

    return 0;
}
